#include <stdio.h>

int main() {
    int T, N;
    if (scanf("%d", &T) != 1) return 0;
    for (int tc = 0; tc < T; ++tc) {
        if (scanf("%d", &N) != 1) return 0;
        for (int i = 1; i <= N; ++i) {
            for (int j = 0; j < i; ++j) putchar('*');
            putchar('\n');
        }
    }
    return 0;
}

